#define MAX_VAL 100001

int longestBalanced(int* nums, int numsSize) {
    int maxLen = 0;
    for (int i = 0; i < numsSize; i++) {
        int odd[MAX_VAL] = {0};
        int even[MAX_VAL] = {0};
        int oddCount = 0;
        int evenCount = 0;

        for (int j = i; j < numsSize; j++) {
            int val = nums[j];
            if (val & 1) {
                if (odd[val] == 0) {
                    oddCount++;
                }
                odd[val]++;
            } else {
                if (even[val] == 0) {
                    evenCount++;
                }
                even[val]++;
            }
            if (oddCount == evenCount) {
                maxLen = fmax(maxLen, j - i + 1);
            }
        }
    }

    return maxLen;
}
